#!/usr/bin/env bash
set -euo pipefail

# E2E Test: fastmcp dev command
# Tests development mode with hot reloading

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(dirname "$SCRIPT_DIR")"
LOG_FILE="/tmp/fastmcp_dev_e2e_$(date +%Y%m%d_%H%M%S).log"
TEST_PROJECT="/tmp/fastmcp_test_project_$$"

log() {
    local level="$1"
    shift
    echo "[$(date +%H:%M:%S)] [$level] $*" | tee -a "$LOG_FILE"
}

cleanup() {
    log "INFO" "Cleaning up..."
    rm -rf "$TEST_PROJECT"
    [[ -n "${DEV_PID:-}" ]] && kill "$DEV_PID" 2>/dev/null || true
}
trap cleanup EXIT

log "INFO" "=== FastMCP Dev E2E Test ==="
log "INFO" "Log file: $LOG_FILE"

# Create test project
log "INFO" "Creating test project at $TEST_PROJECT"
mkdir -p "$TEST_PROJECT/src"

cat > "$TEST_PROJECT/Cargo.toml" << 'EOF'
[package]
name = "test-mcp-server"
version = "0.1.0"
edition = "2021"
EOF

cat > "$TEST_PROJECT/src/main.rs" << 'EOF'
fn main() {
    eprintln!("VERSION=1");
    loop { std::thread::sleep(std::time::Duration::from_secs(1)); }
}
EOF

# Build fastmcp CLI
log "INFO" "Building fastmcp CLI..."
cargo build -p fastmcp-cli 2>&1 | tee -a "$LOG_FILE"

FASTMCP="./target/debug/fastmcp"

# Test 1: Start dev mode
log "INFO" "Test 1: Starting dev mode"
$FASTMCP dev "$TEST_PROJECT" --no-reload > /tmp/dev_output_$$.log 2>&1 &
DEV_PID=$!
sleep 5

if kill -0 "$DEV_PID" 2>/dev/null; then
    log "INFO" "PASS: Dev mode started"
else
    log "ERROR" "FAIL: Dev mode failed to start"
    cat /tmp/dev_output_$$.log
    exit 1
fi

# Check initial version
if grep -q "VERSION=1" /tmp/dev_output_$$.log; then
    log "INFO" "PASS: Initial version running"
else
    log "ERROR" "FAIL: Initial version not detected"
    exit 1
fi

# Kill for reload test
kill "$DEV_PID" 2>/dev/null || true
sleep 1

# Test 2: Hot reload
log "INFO" "Test 2: Hot reload on file change"
$FASTMCP dev "$TEST_PROJECT" > /tmp/dev_output_$$.log 2>&1 &
DEV_PID=$!
sleep 5

# Modify source
cat > "$TEST_PROJECT/src/main.rs" << 'EOF'
fn main() {
    eprintln!("VERSION=2");
    loop { std::thread::sleep(std::time::Duration::from_secs(1)); }
}
EOF

# Wait for rebuild and restart
sleep 10

if grep -q "VERSION=2" /tmp/dev_output_$$.log; then
    log "INFO" "PASS: Hot reload worked"
else
    log "WARN" "SKIP: Hot reload verification inconclusive"
fi

# Test 3: Clean shutdown
log "INFO" "Test 3: Clean shutdown on Ctrl+C"
kill -INT "$DEV_PID"
sleep 2

if kill -0 "$DEV_PID" 2>/dev/null; then
    log "ERROR" "FAIL: Process should have exited"
    kill -9 "$DEV_PID" 2>/dev/null || true
    exit 1
else
    log "INFO" "PASS: Clean shutdown"
fi

log "INFO" "=== All fastmcp dev E2E tests passed! ==="
