```rust
use tracing::{debug, info, warn, error, instrument, Span};
use console::{style, Emoji};

static LOOKING_GLASS: Emoji<'_, '_> = Emoji("🔍 ", "");
static HAMMER: Emoji<'_, '_> = Emoji("🔨 ", "");
static ROCKET: Emoji<'_, '_> = Emoji("🚀 ", "");
static WARNING: Emoji<'_, '_> = Emoji("⚠️ ", "");

impl DevRunner {
    #[instrument(level = "info", skip(self))]
    async fn build_and_start(&mut self) -> Result<()> {
        println!("{} {}Building project...", HAMMER, style("").bold());
        info!(target = %self.config.target, "Starting build");

        let build_start = Instant::now();
        let status = self.run_build().await?;
        let build_time = build_start.elapsed();

        if status.success() {
            println!(
                "{} {}Built in {:.1}s",
                style("✓").green().bold(),
                style("").bold(),
                build_time.as_secs_f32()
            );
            info!(elapsed_ms = build_time.as_millis(), "Build successful");

            self.start_server().await?;
        } else {
            println!(
                "{} {}Build failed",
                WARNING,
                style("").bold().red()
            );
            warn!("Build failed, waiting for changes");
        }

        Ok(())
    }

    #[instrument(level = "debug", skip(self))]
    async fn handle_file_change(&mut self, path: &Path) {
        debug!(path = %path.display(), "File change detected");
        println!(
            "{} {}Changed: {}",
            LOOKING_GLASS,
            style("").bold(),
            style(path.display()).cyan()
        );
    }

    #[instrument(level = "info", skip(self))]
    async fn start_server(&mut self) -> Result<()> {
        println!(
            "{} {}Starting server on {}:{}",
            ROCKET,
            style("").bold(),
            self.config.host,
            self.config.port
        );
        info!(host = %self.config.host, port = self.config.port, "Starting server");

        // ... spawn process
    }
}
